WORKSPACE_LIMITS = {
    "wkspc_01engineering":   20_000_000,   # high-usage team
    "wkspc_02datascience":   10_000_000,
    "wkspc_03legal":          2_000_000,   # low-volume but sensitive
    "wkspc_04experiments":    1_000_000,   # sandbox — keep tight
}

for ws_id, limit in WORKSPACE_LIMITS.items():
    client.admin.workspaces.usage_limits.update(
        workspace_id=ws_id,
        monthly_token_limit=limit
    )
    print(f"Set {ws_id}: {limit:,} tokens/month")

import anthropic, os, requests
from datetime import date

SLACK_WEBHOOK = os.environ["SLACK_WEBHOOK_URL"]
ADMIN_KEY     = os.environ["ANTHROPIC_ADMIN_KEY"]

THRESHOLDS = {
    "critical": 95,   # @channel alert
    "warning":  80,   # info post
}

WORKSPACE_LIMITS = {
    "wkspc_01engineering": 20_000_000,
    "wkspc_02datascience": 10_000_000,
}

client = anthropic.Anthropic(api_key=ADMIN_KEY)

def post_slack(msg: str, urgent: bool = False) -> None:
    text = (f"<!channel> {msg}" if urgent else msg)
    requests.post(SLACK_WEBHOOK, json={"text": text}, timeout=10)

today = date.today()
start = today.replace(day=1).isoformat()
end   = today.isoformat()

usage = client.admin.usage.retrieve(
    start_date=start, end_date=end, group_by="workspace"
)
usage_map = {e.workspace_id: e.input_tokens + e.output_tokens
             for e in usage.data}

for ws_id, cap in WORKSPACE_LIMITS.items():
    used = usage_map.get(ws_id, 0)
    pct  = (used / cap) * 100

    if pct >= THRESHOLDS["critical"]:
        post_slack(
            f":rotating_light: Claude workspace *{ws_id}* at {pct:.0f}% "
            f"({used:,}/{cap:,} tokens). Inference will block at 100%.",
            urgent=True
        )
    elif pct >= THRESHOLDS["warning"]:
        post_slack(
            f":warning: Claude workspace *{ws_id}* at {pct:.0f}% "
            f"({used:,}/{cap:,} tokens) this month."
        )
